import axios from 'axios';
import React, { useMemo, useState } from 'react'
import { useLocation, useNavigate } from 'react-router-dom';
import Loader from './Loader';

const Makepayment = () => {

    const location = useLocation();
    const { product, checkoutItem } = location.state || {}

    const paymentItem = useMemo(() => {
        if (checkoutItem) {
            return checkoutItem;
        }

        if (product) {
            return {
                title: product.product_name,
                description: product.product_description,
                image: product.product_photo,
                amount: Number(product.product_cost) || 0,
                type: 'Food Order',
            };
        }

        return null;
    }, [checkoutItem, product]);

    // declare the navigate hook
    const navigate = useNavigate()

    // initialize hooks to manage the state of your application
    const [number, setNumber] = useState("")
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState("");
    const [error, setError] = useState("");

    // create a function that will handle the submit action
    const handlesubmit = async (e) =>{
        // prevent the site from reloading
        e.preventDefault()

        // update the loading hook
        setLoading(true)

        try{
            // create a form data object
            const formdata = new FormData()

            // append the data to the form data
            formdata.append("phone", number)
            formdata.append("amount", paymentItem.amount)

            const response = await axios.post("https://kbenkamotho.alwaysdata.net/api/mpesa_payment", formdata)

            // set loading back to default
            setLoading(false)

            // update the success hook with the message
            setSuccess(response.data.message)
        }
        catch(error){
            // if there is an error respond to error
            setLoading(false)

            // update the error hook with the error message
            setError(error.message)
        }
    }


  return (
    <div className='row justify-content-center'>
        <h1 className="text-success">Make Payment - Lipa na M-Pesa</h1>

        <div className="col-md-1">
            <input type="button"
            className="btn btn-primary"
            value="<- Back"
            onClick={() => navigate("/") } />
        </div>

        <div className="col-md-6 card shadow p-4">
            {!paymentItem ? (
                <div className="card-body">
                    <h2 className="text-danger">No item selected for payment.</h2>
                    <p className="text-dark">Please choose a room, food order, or booking package first.</p>
                </div>
            ) : (
                <>
            {paymentItem.image && (
                <img src={paymentItem.image} alt={paymentItem.title} className='product_img'/>
            )}

            <div className="card-body ">
                <h5 className="text-secondary">{paymentItem.type}</h5>
                <h2 className="text-info"> {paymentItem.title} </h2>

                <p className="text-dark"> {paymentItem.description} </p>

                <h3 className="text-warning">Kes {paymentItem.amount.toLocaleString()} </h3>
                <p className="fw-semibold text-dark">Total before payment: Kes {paymentItem.amount.toLocaleString()}</p> <br />

                <form onSubmit={handlesubmit}>

                     {/* bind the loading hook */}
                    {loading && <Loader />}

                    <h3 className="text-success"> {success} </h3>
                    <h4 className="text-danger"> {error} </h4>


                    <input type="number"
                    className='form-control'
                    placeholder='Enter the Phone number 254XXXXXXX'
                    required
                    value={number}
                    onChange={(e) => setNumber(e.target.value)} /> <br />

                    {/* {number} */}

                    <input type="submit"
                    value="Make Payment"
                    className='btn btn-success' />
                </form>
            </div>
            </>
            )}
        </div>

    </div>
  )
}

export default Makepayment;
